-- ---------------------------------------------------------- Tabel structuur voor tabel personalia-- --------------------------------------------------------DROP TABLE IF EXISTS personalia;CREATE TABLE personalia (persoon_id smallint(11) NOT NULL auto_increment,user_name varchar(20) NOT NULL default '',emailadres varchar(35) NOT NULL default '',voornaam varchar(20) NOT NULL default '',achternaam varchar(30) NOT NULL default '',paswoord varchar(50) NOT NULL default '',remote_addr varchar(20) NOT NULL default '',confirm_hash varchar(50) NOT NULL default '',is_confirmed smallint(4) default NULL,date_created date default NULL,smsfoon varchar(15) NOT NULL default '',-- smsfoon  foon waarop smsjes ontvangen kunnen wordengebdat date NOT NULL default '0000-00-00',-- jjjj mm ddgender smallint(4) default NULL,-- 1=man 0=vrouwdatabasis varchar(4) NOT NULL default 'nl',PRIMARY KEY (persoon_id),KEY user_name (user_name),KEY emailadres (emailadres)) TYPE=MyISAM AUTO_INCREMENT=100 ;-- -- Gegevens worden uitgevoerd voor tabel personaliaINSERT INTO `personalia` VALUES (6, 'fuzzy', 'info@fuzzybrush.nl', 'Fuzzy', 'Fuzzy', 'eae68a18ec860090845abe5b688e42c2', '213.148.230.117', '492011b5dab3039b3ed6e395bcf86fbf', 1, '2006-10-09', '', '0000-00-00', 0, '');
